-- ============================================================
-- TORQUED — Migration 019: Vehicle + spec + pricing seed (v2)
-- Renamed from 005. Uses vehicle_models (not vehicles).
-- ============================================================

-- Truncate fleet tables if partial data detected from a prior run.
-- Truncating vehicle_models CASCADE clears all FK-dependent tables.
-- part_categories is managed by 018 and must NOT be truncated here.
DO $$
BEGIN
  IF (SELECT count(*) FROM vehicle_models) NOT IN (0, 136) THEN
    RAISE NOTICE 'Partial vehicle_models data detected — truncating fleet tables';
    TRUNCATE vehicle_models CASCADE;
  END IF;
END $$;

